local filename = ngx.var.arg_filename
if not filename then
  return ngx.exit(400)
end

local file, err = io.open("./files/" .. filename)
if not file then
  return ngx.say("Error opening file: " .. err)
end

local content = file:read("*a")
file:close()

ngx.say(content)